                if (_hl_.len == 0) break;
                const _cp = std.mem.indexOfScalar(u8, _hl_, ':') orelse continue;
                const _hn = std.mem.trim(u8, _hl_[0.._cp], " ");
                const _hv = std.mem.trim(u8, _hl_[_cp+1..], " ");
                if (std.ascii.eqlIgnoreCase(_hn, "content-length"))
